import { Routes } from '@angular/router';
import { authGuard, adminGuard, guestGuard } from './core/guards/auth.guard';

export const routes: Routes = [
  // Public routes with layout
  {
    path: '',
    loadComponent: () => import('./layouts/public/public-layout.component').then(m => m.PublicLayoutComponent),
    children: [
      { path: '', loadComponent: () => import('./features/home/home.component').then(m => m.HomeComponent) },
      { path: 'actualites', loadComponent: () => import('./features/articles/articles-list.component').then(m => m.ArticlesListComponent) },
      { path: 'actualites/:id', loadComponent: () => import('./features/articles/article-detail.component').then(m => m.ArticleDetailComponent) },
      { path: 'projets', loadComponent: () => import('./features/projects/projects-list.component').then(m => m.ProjectsListComponent) },
      { path: 'projets/:id', loadComponent: () => import('./features/projects/project-detail.component').then(m => m.ProjectDetailComponent) },
      { path: 'ressources/documents', loadComponent: () => import('./features/documents/documents-list.component').then(m => m.DocumentsListComponent) },
      { path: 'contact', loadComponent: () => import('./features/contact/contact.component').then(m => m.ContactComponent) },
      { path: 'ministere/ministre', loadComponent: () => import('./features/ministere/ministre.component').then(m => m.MinistreComponent) },
      { path: 'ministere/missions', loadComponent: () => import('./features/ministere/missions.component').then(m => m.MissionsComponent) },
      { path: 'ministere/organigramme', loadComponent: () => import('./features/ministere/organigramme.component').then(m => m.OrganigrammeComponent) },
      { path: 'ministere/structures', loadComponent: () => import('./features/ministere/structures.component').then(m => m.StructuresComponent) },
      { path: 'faq', loadComponent: () => import('./features/faq/faq.component').then(m => m.FAQComponent) },
      { path: 'services', loadComponent: () => import('./features/services/services.component').then(m => m.ServicesComponent) },
      { path: 'evenements', loadComponent: () => import('./features/events/events.component').then(m => m.EventsComponent) },
      // Redirections pour compatibilité
      { path: 'articles', redirectTo: 'actualites', pathMatch: 'full' },
      { path: 'articles/:id', redirectTo: 'actualites/:id', pathMatch: 'full' },
      { path: 'projects', redirectTo: 'projets', pathMatch: 'full' },
      { path: 'projects/:id', redirectTo: 'projets/:id', pathMatch: 'full' },
      { path: 'documents', redirectTo: 'ressources/documents', pathMatch: 'full' },
    ]
  },
  
  // Auth routes (no layout)
  { 
    path: 'auth/login', 
    loadComponent: () => import('./features/auth/login.component').then(m => m.LoginComponent),
    canActivate: [guestGuard]
  },
  
  // Admin routes
  {
    path: 'admin',
    loadComponent: () => import('./layouts/admin/admin-layout.component').then(m => m.AdminLayoutComponent),
    canActivate: [adminGuard],
    children: [
      { path: '', redirectTo: 'dashboard', pathMatch: 'full' },
      { path: 'dashboard', loadComponent: () => import('./features/admin/dashboard/dashboard.component').then(m => m.AdminDashboardComponent) },
      { path: 'articles', loadComponent: () => import('./features/admin/articles/admin-articles.component').then(m => m.AdminArticlesComponent) },
      { path: 'projects', loadComponent: () => import('./features/admin/projects/admin-projects.component').then(m => m.AdminProjectsComponent) },
      { path: 'documents', loadComponent: () => import('./features/admin/documents/admin-documents.component').then(m => m.AdminDocumentsComponent) },
      { path: 'contacts', loadComponent: () => import('./features/admin/contacts/admin-contacts.component').then(m => m.AdminContactsComponent) },
      { path: 'users', loadComponent: () => import('./features/admin/users/admin-users.component').then(m => m.AdminUsersComponent) },
    ]
  },
  
  // Fallback
  { path: '**', redirectTo: '' }
];
